    PHONE_NO=#{phone}
WHERE USER_ID = #{userId}

mapper.select:
SELECT COUNT(*)
FROM USER_BASIC
WHERE EMAIL = #{email}

SELECT COUNT(*)
FROM USER_BASIC
WHERE PHONE_NO = #{phone}

